1	const PROCESSING_FEE = 5;
2	
3	type Item = { type: string; cursed?: boolean; enchantment?: number };
4	type Customer = { yearsWithMHPCO: number };
5	type QuoteStep = { op: "quote"; items: Item[] };
6	type Damage = { itemType: string; amount: number };
7	type Incident = { cause: string; damages: Damage[] };
8	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
9	type Step = QuoteStep | ClaimStep;
10	type Scenario = { customer: Customer; steps: Step[] };
11	type QuoteResult = { premium: number };
12	type ClaimResult = { payout: number; remainingCap: number };
13	type StepResult = QuoteResult | ClaimResult;
14	type ScenarioResult = { results: StepResult[] };
15	
16	type ItemSpec = { basePrice: number; insuranceValue: number };
17	
18	const ITEM_CATALOG: Record<string, ItemSpec> = {
19	  sword: { basePrice: 100, insuranceValue: 1000 },
20	  amulet: { basePrice: 60, insuranceValue: 600 },
21	  staff: { basePrice: 80, insuranceValue: 800 },
22	  potion: { basePrice: 40, insuranceValue: 400 },
23	  rune: { basePrice: 25, insuranceValue: 250 },
24	  moonstone: { basePrice: 25, insuranceValue: 250 },
25	};
26	
27	const specOf = (item: Item): ItemSpec | undefined => ITEM_CATALOG[item.type];
28	
29	const basePriceOf = (item: Item): number => specOf(item)?.basePrice ?? 0;
30	
31	const CURSED_SURCHARGE_RATE = 0.5;
32	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
33	const HIGH_ENCHANTMENT_THRESHOLD = 5;
34	
35	const isCursed = (item: Item): boolean => item.cursed === true;
36	const isHighlyEnchanted = (item: Item): boolean =>
37	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
38	
39	const surchargeRate = (item: Item): number =>
40	  (isCursed(item) ? CURSED_SURCHARGE_RATE : 0) +
41	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
42	
43	const itemSurchargeAmount = (item: Item): number =>
44	  basePriceOf(item) * surchargeRate(item);
45	
46	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
47	const BLOCK_SIZE = 3;
48	const BLOCK_PRICE = 60;
49	
50	const groupByType = (items: Item[]): Map<string, Item[]> =>
51	  items.reduce((groups, item) => {
52	    const existing = groups.get(item.type) ?? [];
53	    return groups.set(item.type, [...existing, item]);
54	  }, new Map<string, Item[]>());
55	
56	const qualifiesForComponentBlock = (type: string, members: Item[]): boolean =>
57	  COMPONENT_TYPES.has(type) && members.length === BLOCK_SIZE;
58	
59	const groupBasePremium = (type: string, members: Item[]): number => {
60	  if (qualifiesForComponentBlock(type, members)) return BLOCK_PRICE;
61	  return members.reduce((sum, item) => sum + basePriceOf(item), 0);
62	};
63	
64	const itemsBaseSubtotal = (items: Item[]): number =>
65	  Array.from(groupByType(items)).reduce(
66	    (total, [type, members]) => total + groupBasePremium(type, members),
67	    0,
68	  );
69	
70	const itemsSurchargeSubtotal = (items: Item[]): number =>
71	  items.reduce((sum, item) => sum + itemSurchargeAmount(item), 0);
72	
73	const LOYALTY_DISCOUNT_RATE = 0.2;
74	const LOYALTY_YEARS_THRESHOLD = 2;
75	
76	const isLoyalCustomer = (customer: Customer): boolean =>
77	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
78	
79	const loyaltyDiscountRate = (customer: Customer): number =>
80	  isLoyalCustomer(customer) ? LOYALTY_DISCOUNT_RATE : 0;
81	
82	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
83	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
84	
85	const hasPreviousContract = (stepIndex: number): boolean => stepIndex > 0;
86	
87	const followUpDiscountRate = (stepIndex: number): number =>
88	  hasPreviousContract(stepIndex) ? FOLLOW_UP_DISCOUNT_RATE : 0;
89	
90	const policyAdjustmentRate = (customer: Customer, stepIndex: number): number =>
91	  FIRST_INSURANCE_SURCHARGE_RATE -
92	  loyaltyDiscountRate(customer) -
93	  followUpDiscountRate(stepIndex);
94	
95	const quotePremium = (
96	  items: Item[],
97	  customer: Customer,
98	  stepIndex: number,
99	): number => {
100	  const baseSubtotal = itemsBaseSubtotal(items);
101	  const surchargeSubtotal = itemsSurchargeSubtotal(items);
102	  // Kept as `base + base*rate` (not `base*(1+rate)`) for IEEE-754 stability:
103	  // e.g. 100*(1+0.1) === 110.00000000000001, which trips Math.ceil rounding.
104	  return (
105	    baseSubtotal +
106	    baseSubtotal * policyAdjustmentRate(customer, stepIndex) +
107	    surchargeSubtotal +
108	    PROCESSING_FEE
109	  );
110	};
111	
112	// MHPCO always rounds in its own favor: premiums up, payouts down.
113	const roundPremiumInMhpcoFavor = (amount: number): number => Math.ceil(amount);
114	
115	const insuranceValueOf = (item: Item): number =>
116	  specOf(item)?.insuranceValue ?? 0;
117	
118	const DEDUCTIBLE_PER_DAMAGE = 100;
119	const CAP_MULTIPLIER = 2;
120	
121	const insuranceSum = (items: Item[]): number =>
122	  items.reduce((sum, item) => sum + insuranceValueOf(item), 0);
123	
124	const damagePayout = (damage: Damage): number =>
125	  damage.amount - DEDUCTIBLE_PER_DAMAGE;
126	
127	const runQuoteStep = (
128	  step: QuoteStep,
129	  customer: Customer,
130	  stepIndex: number,
131	): QuoteResult => ({
132	  premium: roundPremiumInMhpcoFavor(quotePremium(step.items, customer, stepIndex)),
133	});
134	
135	const runClaimStep = (step: ClaimStep, policyItems: Item[]): ClaimResult => {
136	  const payout = step.incident.damages.reduce(
137	    (sum, damage) => sum + damagePayout(damage),
138	    0,
139	  );
140	  const cap = CAP_MULTIPLIER * insuranceSum(policyItems);
141	  return { payout, remainingCap: cap - payout };
142	};
143	
144	const runStep = (
145	  step: Step,
146	  customer: Customer,
147	  stepIndex: number,
148	  steps: Step[],
149	): StepResult => {
150	  if (step.op === "quote") return runQuoteStep(step, customer, stepIndex);
151	  const policyStep = steps[step.policy] as QuoteStep;
152	  return runClaimStep(step, policyStep.items);
153	};
154	
155	export const runScenario = (input: Scenario): ScenarioResult => ({
156	  results: input.steps.map((step, i) =>
157	    runStep(step, input.customer, i, input.steps),
158	  ),
159	});
